<template>
    <div class="addClient">
      <div class="row">
        <div class="col-8">
          <div class="add_davernis">
            <div class="form_header">
              <h5 class="mb-0">{{ client_id ? $t('edit_client') : $t('add_client') }}</h5>
            </div>

            <div class="form_card">
              <div class="form_section">
                <div class="form_row">
                  <div class="form_group">
                    <label class="form_label">{{$t('fio')}} <span class="text-danger">*</span></label>
                    <mdb-input class="modern_input m-0" v-model="name" @input="SearchClientNamePass($event)" size="md" outline group type="text" validate error="wrong" success="right"/>
                    <small class="invalid-text" v-if="$v.name.$dirty && !$v.name.required">
                      {{$t('name_invalid_text')}}
                    </small>
                  </div>
                </div>

                <div class="form_row">
                  <div class="form_group">
                    <label class="form_label">{{$t('phone_number')}}</label>
                    <input 
                      class="phone_input" 
                      v-model="phone_number" 
                      @input="formatPhoneNumber" 
                      type="text" 
                      :placeholder="$t('phone_number')"
                    />
                  </div>
                  <div class="form_group">
                    <label class="form_label">{{$t('passport_number')}} <span class="text-danger">*</span></label>
                    <mdb-input class="modern_input m-0" v-model="passport_number" @input="SearchClientNamePass($event)" size="md" outline group type="text" validate error="wrong" success="right"/>
                    <small class="invalid-text" v-if="$v.passport_number.$dirty && !$v.passport_number.required">
                      {{$t('name_invalid_text')}}
                    </small>
                  </div>
                </div>

                <div class="form_row">
                  <div class="form_group">
                    <label class="form_label">{{$t('address')}}</label>
                    <mdb-input class="modern_input m-0" v-model="address" size="md" outline group type="text" validate error="wrong" success="right"/>
                  </div>
                  <div class="form_group">
                    <label class="form_label">{{$t('born_date')}}</label>
                    <mdb-input class="modern_input m-0" v-model="born_date" size="md" outline group type="date" validate error="wrong" success="right"/>
                  </div>
                </div>
              </div>

              <div class="form_section">
                <h6 class="section_title">{{$t('picture')}}</h6>
                <div class="image_upload_section">
                  <div class="image_preview_container">
                    <div class="image_preview_item" v-show="!PicShow && image">
                      <img :src="hostname + image" id="prewImageClientAdd" class="preview_image" alt="Passport">
                      <div class="image_delete_btn" @click="delImage">
                        <mdb-icon icon="times" />
                      </div>
                    </div>
                    <div class="image_preview_item" v-show="!PicShow && image2">
                      <img :src="hostname + image2" class="preview_image" alt="Passport 2">
                    </div>
                    <div class="image_preview_item" v-if="photo_url">
                      <img :src="hostname + photo_url" class="preview_image" alt="Photo">
                    </div>
                  </div>
                  <input hidden id="inputFileToLoad" @change="previewFile()" accept="image/png, image/gif, image/jpeg" type="file" ref="file_Img"/>
                  <div class="upload_buttons">
                    <button type="button" @click="scanerFile" class="upload_btn">
                      <mdb-icon icon="file-image" class="mr-2"/>
                      {{$t('passport_image')}}
                    </button>
                    <button type="button" @click="showPhoto = true" class="upload_btn">
                      <mdb-icon icon="camera" class="mr-2"/>
                      {{$t('photo')}}
                    </button>
                  </div>
                </div>
              </div>

              <div class="form_section">
                <h6 class="section_title">{{$t('additional_info')}}</h6>
                <div class="form_row">
                  <div class="form_group full_width">
                    <label class="form_label">{{$t('note')}}</label>
                    <mdb-input class="modern_input m-0" v-model="note" @input="SearchClientNote($event)" size="md" outline group type="textarea" validate error="wrong" success="right"/>
                  </div>
                </div>
                <div class="form_row">
                  <div class="form_group">
                    <label class="form_label checkbox_label">
                      <input v-model="oshibka" type="checkbox" class="modern_checkbox"/>
                      <span class="checkbox_text text-danger">{{$t('oshibka')}}</span>
                    </label>
                  </div>
                </div>
              </div>

              <div class="form_actions">
                <mdb-btn v-if="client_id" @click="next_data" color="primary" class="action_btn">
                  <mdb-icon icon="arrow-right" class="mr-2"/>
                  {{$t('continue')}}
                </mdb-btn>
                <mdb-btn @click="save_data" color="success" class="action_btn">
                  <mdb-icon icon="check" class="mr-2"/>
                  {{$t('add')}}
                </mdb-btn>
              </div>
            </div>
              
            <webcam v-if="showPhoto" @getPhotosub="takePhoto"/>
            <Toast ref="message"></Toast>
          </div>
        </div>
        <div class="col-4">
          <div class="client_list_container">
            <div class="client_list_header">
              <h6 class="mb-0">{{$t('client_list')}}</h6>
              <small class="text-muted">{{ client_list.rows.length }} {{$t('clients')}}</small>
            </div>
            <div class="user_illSendPatient">
              <div v-for="(item,i) in client_list.rows" :key="i" 
                class="client_list_item" 
                @click="getBemorId(i,item)" 
                :class="{'activeUser' : active_bemor == i }">
                <div class="client_item_content">
                  <div class="client_avatar">
                    <mdb-icon icon="user" />
                  </div>
                  <div class="client_info">
                    <p class="client_name">{{item.fio}}</p>
                    <div class="client_details">
                      <span class="client_detail_item">
                        <mdb-icon icon="calendar-alt" class="mr-1"/>
                        {{item.addiotionala_information}}
                      </span>
                      <span class="client_detail_item">
                        <mdb-icon icon="phone" class="mr-1"/>
                        {{item.phone_number}}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
              <div v-if="client_list.rows.length === 0" class="empty_state">
                <mdb-icon icon="users" style="font-size: 48px; color: #ccc;"/>
                <p class="text-muted mt-2">{{$t('no_clients_found')}}</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
</template>
    
    <script>
    import erpSelect from "../../components/erpSelect.vue";
    import {mdbRow, mdbCol, mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
    import { required } from 'vuelidate/lib/validators'
    import webcam from '../webcam/webcam_Add.vue'
    import {mapActions,mapGetters} from 'vuex'
    export default {
      components:{
        mdbRow, mdbCol, mdbInput, mdbBtn, mdbIcon, webcam, erpSelect
      },
      validations: {
          name: {required},
          // phone_number: {required},
          passport_number: {required},
          // district_name : {required},
          // clientgroup_name : {required},
        },
      data() {
        return {
          hostname: this.$store.state.server_ip,
          name: '',
          id: 0,
          phone_number: '',
          passport_number: '',
          client_group_name: '',
          client_group_id:null,
          born_date: '',
          address: '',
          note: '',
          active_bemor: -1,
          showPhoto: false,
          photo_url: '',
          car_number: '',
          loading: false,
          client_id : null,
          client_data : {},

          PicShow: true,
          base64: '',
          image: '',
          image2: '',
          client_list: {
            rows:[]
          },
          oshibka: false,
          auth_user_updator_id: 0,
        }
      },
      // props:{
      //   client_id: {
      //     type: Number,
      //     default: null,
      //   }
      // },
       computed: mapGetters(['all_district_t', 'all_client_controler', 'allClient']),
      async mounted(){
          // this.fetch_district_t();
          // this.fetch_client_controler();
          await this.fetchClientLast();
        },
      methods: {
        ...mapActions(['fetch_district_t', 'fetch_client_controler', 'fetchClient']),
        delImage(){
          this.base64 = ''
          this.PicShow = true
          this.image = ''
        },
        selectOption(option){
          this.client_group_name = option.name;
          this.client_group_id = option.id;
        },
    
        async previewFile(){
          const preview = document.getElementById('prewImageClientAdd');
            const file = document.querySelector('input[type=file]').files[0];
            this.PicShow = true;
          var reader = new FileReader();
          reader.addEventListener("load", function () {
            this.image =  reader.result;
            preview.src = reader.result;
          }, true);
          if (file) {
              this.PicShow = false
            reader.readAsDataURL(file);
          }
        },
        takePhoto(img){
          console.log(img)
          this.photo_url = img;
          this.showPhoto = false;
        },
        MountedFunc(){
          this.id = 0;
          this.clv_ws();
          this.active_bemor = -1;
          this.oshibka = false;
          this.auth_user_updator_id = 0;
        },
        fetchPassword_client(length) {
          var result = '';
          var characters  = 'abcdefghijklmnopqrstuvwxyz123456789';
          var charactersLength = characters.length;
          for ( var i = 0; i < length; i++ ) {
              result += characters.charAt(Math.floor(Math.random() * charactersLength));
          }
          return result;
        },
        async getBemorId(i, data){
          this.car_number = data.car_number;
          if(data.car_number == null){
            this.car_number = await this.fetchPassword_client(5);
          }
          this.client_data = data;
          this.active_bemor = i;
          this.name = data.fio;
          this.id = data.id;
          // Telefon raqamini formatlash
          if(data.phone_number){
            let numbers = data.phone_number.replace(/\D/g, '');
            if (numbers.length > 0) {
              if (numbers.length <= 2) {
                this.phone_number = '(' + numbers;
              } else if (numbers.length <= 5) {
                this.phone_number = '(' + numbers.slice(0, 2) + ') ' + numbers.slice(2);
              } else {
                this.phone_number = '(' + numbers.slice(0, 2) + ') ' + numbers.slice(2, 5) + '-' + numbers.slice(5, 9);
              }
            } else {
              this.phone_number = data.phone_number;
            }
          } else {
            this.phone_number = '';
          }
          this.passport_number = data.passport_number;
          this.address = data.adddress;
          this.note = data.note;
          this.client_id = data.id;
          this.born_date = data.addiotionala_information;
          if(data.group){
            this.client_group_name = data.group.name;
            this.client_group_id = data.group.id;
          }
          this.image = data.passport_image_base_64;
          this.photo_url = data.image_url;
          this.image2 = data.passport_image_url;
    
          if(data.auth_user_updator_id == 1){
            this.oshibka = true;
          }
          else{
            this.oshibka = false;
          }
    
          this.PicShow = false;
        },
        clv_ws(){
          this.name = '';
          this.id = 0;
          this.phone_number = '';
          this.passport_number = '';
          this.address = '';
          this.note = '';
          this.base64 = '';
          this.born_date = '';
          this.client_group_name = '';
          this.client_group_id = null,
          this.image = '';
          this.image2 = '';
          this.photo_url = '';
          this.showPhoto = false;
          this.PicShow = true;
          this.car_number = '';
    
        },
    
        next_data(){
          this.id = 0;
          this.$emit('close_data', this.client_data)
        },
    
    
        save_data :  async function(){
          if(this.oshibka == false){
            this.auth_user_updator_id = 0;
          }
          else{
            this.auth_user_updator_id = 1;
          }
          // console.log(this.base64)
          if(this.$v.$invalid)
          {
            this.$v.$touch();
            this.$refs.message.warning('please_fill')
            return false;
          }
          if(this.id == 0){
            this.car_number = await this.fetchPassword_client(5);
          }
          // Telefon raqamini formatdan tozalash (faqat raqamlarni yuborish)
          let cleanPhoneNumber = this.phone_number.replace(/\D/g, '');
          
          const requestOptions = {
            method : "POST",
            headers: { "Content-Type" : "application/json" },
            body: JSON.stringify({
              "fio" : this.name,
              "adddress" : this.address,
              "passport_number" : this.passport_number,
              "phone_number": cleanPhoneNumber,
              "addiotionala_information": this.born_date,
              "tegirmonClientGroupid" : this.client_group_id,
              "note" : this.note,
              "image_url": this.photo_url,
              "passport_image_base_64": this.image,
              "passport_image_url": this.image2,
              "car_number": this.car_number,
              "id" : this.id,
              "auth_user_updator_id": this.auth_user_updator_id
            })
          };
          try{
            this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews", requestOptions);
            this.loading = false;
            if(response.status == 201 || response.status == 200)
            {
            console.log('dasdas')
    
              const tryjson = await response.json();
              console.log(tryjson)
              this.clv_ws();
              this.$emit('close_data', tryjson)
              this.$refs.message.success('Added_successfully')
              // console.log('fire' + i)
            }
            else{
              const data = await response.text();
              this.modal_info = data;
              this.modal_status = true;
              
            }
          }
          catch{
            this.loading = false;
            this.modal_info = this.$i18n.t('network_ne_connect'); 
            this.modal_status = true;
          }
        },
        async fetchClientLast(){
          try{
            // this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getPagination?page=0&size=100");
            const data = await response.json();
            console.log('weqeqw')
            console.log(data)
            // this.loading = false;
            if(response.status == 201 || response.status == 200)
            {
              this.client_list.rows = data.items_list;
             
              return true;
            }
            else{
              // const data = await response.text();
              this.modal_info = data;
              this.modal_status = true;
              return false;
            }
          }
          catch{
            // this.loading = false;
            this.client_list.rows = [];
            this.modal_info = this.$i18n.t('network_ne_connect');
            this.modal_status = true;
          }
        },
    
        formatPhoneNumber(event){
          let value = event.target.value;
          // Faqat raqamlarni qoldirish
          let numbers = value.replace(/\D/g, '');
          
          // Maksimal 9 ta raqam
          if (numbers.length > 9) {
            numbers = numbers.slice(0, 9);
          }
          
          // Formatlash: (XX) XXX-XXXX
          let formatted = '';
          if (numbers.length > 0) {
            if (numbers.length <= 2) {
              formatted = '(' + numbers;
            } else if (numbers.length <= 5) {
              formatted = '(' + numbers.slice(0, 2) + ') ' + numbers.slice(2);
            } else {
              formatted = '(' + numbers.slice(0, 2) + ') ' + numbers.slice(2, 5) + '-' + numbers.slice(5, 9);
            }
          }
          
          // To'g'ridan-to'g'ri qiymatni o'rnatish
          this.phone_number = formatted;
          
          // Input elementini yangilash
          event.target.value = formatted;
          
          // Search funksiyasini chaqirish
          if (formatted.length > 0) {
            this.SearchClientNamePass(formatted);
          } else {
            this.fetchClientLast();
          }
        },
        async SearchClientNamePass(search){
          console.log('search')
          console.log(search)
          if(search == ''){
          await this.fetchClientLast();
            return
          }
          // /TegirmonClient/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=
          try{
            // this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=" + search);
            const data = await response.json();
            console.log('weqeqw')
            console.log(data)
            // this.loading = false;
            if(response.status == 201 || response.status == 200)
            {
              this.client_list.rows = data.items_list;
              if(data.items_list == 0){
                // this.$refs.message.error('not_client')
              }
              // this.$refs.message.success('Added_successfully')
              return true;
            }
            else{
              // const data = await response.text();
              this.modal_info = data;
              this.modal_status = true;
              return false;
            }
          }
          catch{
            // this.loading = false;
            this.client_list = this.allClient;
            this.modal_info = this.$i18n.t('network_ne_connect');
            this.modal_status = true;
          }
          
        },
        async SearchClientNote(search){
          console.log('search')
          console.log(search)
          if(search == ''){
          await this.fetchClientLast();
            return
          }
          // /TegirmonClient/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=
          try{
            // this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getPaginationByNote?page=0&size=100&note_str=" + search);
            const data = await response.json();
            console.log('weqeqw')
            console.log(data)
            // this.loading = false;
            if(response.status == 201 || response.status == 200)
            {
              this.client_list.rows = data.items_list;
              if(data.items_list == 0){
                // this.$refs.message.error('not_client')
              }
              // this.$refs.message.success('Added_successfully')
              return true;
            }
            else{
              // const data = await response.text();
              this.modal_info = data;
              this.modal_status = true;
              return false;
            }
          }
          catch{
            // this.loading = false;
            this.client_list = this.allClient;
            this.modal_info = this.$i18n.t('network_ne_connect');
            this.modal_status = true;
          }
          
        },
        async SearchClientBornDate(search){
          console.log('search')
          console.log(search)
          if(search == ''){
            await this.fetchClientLast();
            return
          }
          // /TegirmonClient/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number=
          try{
            // this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getPaginationByBornDate?page=0&size=100&born_date_str=" + search);
            const data = await response.json();
            console.log('weqeqw')
            console.log(data)
            // this.loading = false;
            if(response.status == 201 || response.status == 200)
            {
              this.client_list.rows = data.items_list;
              if(data.items_list == 0){
                // this.$refs.message.error('not_client')
              }
              // this.$refs.message.success('Added_successfully')
              return true;
            }
            else{
              // const data = await response.text();
              this.modal_info = data;
              this.modal_status = true;
              return false;
            }
          }
          catch{
            // this.loading = false;
            this.client_list = this.allClient;
            this.modal_info = this.$i18n.t('network_ne_connect');
            this.modal_status = true;
          }
        },
    
        async scanerFile()
        {
            scanner.scan(this.displayImagesOnPage,
            {
                "output_settings" :
                [
                  {
                      "type" : "return-base64",
                      "format" : "jpg"
                  }
                ]
            }
            );
          },
          displayImagesOnPage(successful, mesg, response) {
            if(!successful) { // On error
                console.error('Failed: ' + mesg);
                return;
            }
    
            if(successful && mesg != null && mesg.toLowerCase().indexOf('user cancel') >= 0) { // User canceled.
                console.info('User canceled');
                return;
            }
    
            var scannedImages = scanner.getScannedImages(response, true, false); // returns an array of ScannedImage
            this.processScannedImage(scannedImages);
            //for(var i = 0; (scannedImages instanceof Array) && i < scannedImages.length; i++) {
            //    var scannedImage = scannedImages[i];   
            //}
          },
    
          processScannedImage(scannedImage) {
            var imagesScanned = [];
            console.log(scannedImage.length)
            imagesScanned.push(scannedImage[0]);
            this.fetchBase64ToHttpImg(scannedImage[0].src);
            if(scannedImage.length>1){
              this.fetchBase64ToHttpImg2(scannedImage[1].src);
            }
            console.log(this.image)
            this.PicShow = false;
          },
    
          async fetchBase64ToHttpImg(img){
            try{
              const requestOptions = {
                method : "POST",
                headers: { "Content-Type" : "application/json" },
                body: JSON.stringify({
                  "image_base_64" : img,
                })
              };
              const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getSaveBase64ImageToFolderAndGetImageUrl", requestOptions);
              // console.log(response)
              const data = await response.json();
              console.log(data)
              if(response.status == 201 || response.status == 200)
              {
                this.image = data.image_url_str;
              }
              else{
                this.image = '';
              }
            }
            catch{
              this.image = '';
            }
          },
          async fetchBase64ToHttpImg2(img){
            try{
              const requestOptions = {
                method : "POST",
                headers: { "Content-Type" : "application/json" },
                body: JSON.stringify({
                  "image_base_64" : img,
                })
              };
              const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getSaveBase64ImageToFolderAndGetImageUrl", requestOptions);
              // console.log(response)
              const data = await response.json();
              console.log(data)
              if(response.status == 201 || response.status == 200)
              {
                this.image2 = data.image_url_str;
              }
              else{
                this.image2 = '';
              }
            }
            catch{
              this.image2 = '';
            }
          }
      },
    }
    </script>
    
    <style lang="scss" scoped>
    .addClient {
      background: linear-gradient(135deg, #f9feff 0%, #f7fbff 100%);
      min-height: calc(100vh - 140px);
      padding: 20px;
    }

    .add_davernis {
      background: white;
      border-radius: 12px;
      box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
      padding: 24px;
      
    }

    .form_header {
      margin-bottom: 24px;
      padding-bottom: 16px;
      border-bottom: 2px solid #f0f0f0;
      
      
      h5 {
        color: #344767;
        font-weight: 600;
      }
    }

    .form_card {
      .form_section {
        margin-bottom: 16px;
        
        &:last-child {
          margin-bottom: 0;
        }
      }

      .section_title {
        color: #344767;
        font-weight: 600;
        font-size: 15px;
        margin-bottom: 10px;
        padding-bottom: 6px;
        border-bottom: 1px solid #e9ecef;
      }
    }

    .form_row {
      display: flex;
      gap: 12px;
      margin-bottom: 10px;

      .form_group {
        flex: 1;
        
        &.full_width {
          flex: 1 1 100%;
        }
      }
    }

    .form_label {
      display: block;
      color: #67748E;
      font-size: 13px;
      font-weight: 500;
      margin-bottom: 0px;
